from collections import deque

class Solution:
    def maximumBinaryString(self, binary):
        seen = {binary}
        dq = deque([binary])
        best = binary
        while dq:
            cur = dq.popleft()
            if cur > best:
                best = cur
            for i in range(len(cur) - 1):
                pair = cur[i:i + 2]
                if pair == '00':
                    nxt = cur[:i] + '10' + cur[i + 2:]
                elif pair == '10':
                    nxt = cur[:i] + '01' + cur[i + 2:]
                else:
                    continue
                if nxt not in seen:
                    seen.add(nxt)
                    dq.append(nxt)
        return best

