class Solution:
    def maximumBinaryString(self, binary: str) -> str:
        zeros = binary.count('0')
        if zeros == 0:
            return binary
        ones = len(binary) - zeros
        first_zero = binary.index('0')
        ones_after = ones - first_zero
        return '1' * first_zero + '1' * (zeros - 1) + '0' + '1' * ones_after

