var maximumBinaryString = function(binary) {
  const zeros = (binary.match(/0/g) || []).length;
  if (zeros === 0) return binary;
  const ones = binary.length - zeros;
  const firstZero = binary.indexOf('0');
  const onesAfter = ones - firstZero;
  return '1'.repeat(firstZero) + '1'.repeat(zeros - 1) + '0' + '1'.repeat(onesAfter);
};
